{
  "grammar": [
    {
      "pattern": "Subject + 天氣 + 很 + Adjective",
      "structure": ["Subject", "天氣", "很", "Adjective"],
      "explanation_en": "Use '很' to link weather with an adjective. '很' softens the adjective and doesn't always mean 'very'.",
      "title": "天氣很 + Adjective",
      "meaning": "The weather is [adjective]",
      "when_to_use": ["Describing current weather", "Making small talk about weather"],
      "when_not_to_use": ["When using '很' with a verb", "When the adjective already implies intensity (e.g., '好熱')"],
      "pragmatic_notes": "In Taiwan, '很' is often used as a neutral linker, not emphasizing 'very'. For strong emphasis, use '好' or '真'.",
      "word_order_notes": "Subject + 天氣 + 很 + Adjective. Do not omit '很' in affirmative sentences.",
      "english_contrast": "English says 'The weather is hot' without a linker. Chinese requires '很'.",
      "korean_contrast": "Korean uses '날씨가 + Adjective + 아/어요' without a separate linker. Chinese uses '很'.",
      "negative_examples": [
        {
          "text": "天氣熱",
          "error": "Missing '很' makes it sound like a comparison or incomplete."
        }
      ],
      "incorrect_examples": [
        {
          "text": "天氣很熱嗎",
          "error": "In questions, '很' is optional but acceptable. This is actually correct; no error here."
        }
      ],
      "transformation_drills": ["Change '天氣很熱' to negative: '天氣不熱'", "Change '天氣很冷' to question: '天氣很冷嗎'"],
      "production_drills": ["Describe today's weather using '天氣很 + Adjective'", "Ask a friend about the weather using this pattern"],
      "common_error_patterns": ["Omitting '很' in affirmative sentences", "Using '很' with verbs like '下雨'"],
      "repair_feedback": {
        "word_order": "Put '很' before the adjective, not after.",
        "politeness": "Using '很' makes the statement sound natural and polite.",
        "vocabulary": "Use weather adjectives like 熱, 冷, 舒服, 涼快."
      }
    },
    {
      "pattern": "Subject + 有點 + Adjective",
      "structure": ["Subject", "有點", "Adjective"],
      "explanation_en": "Use '有點' to express that something is 'a little' or 'slightly' in a negative or neutral sense.",
      "title": "有點 + Adjective",
      "meaning": "A little [adjective] (often negative)",
      "when_to_use": ["Expressing mild dissatisfaction", "Describing slight feelings or weather"],
      "when_not_to_use": ["For positive emphasis (use '很' or '好')", "With very strong adjectives like '太'"],
      "pragmatic_notes": "In Taiwan, '有點' is common for polite complaints about weather or mood, e.g., '天氣有點熱'.",
      "word_order_notes": "Subject + 有點 + Adjective. Do not add '很' after '有點'.",
      "english_contrast": "English uses 'a little' before the adjective. Chinese uses '有點' before the adjective.",
      "korean_contrast": "Korean uses '조금 + Adjective + 아/어요'. Chinese uses '有點 + Adjective'.",
      "negative_examples": [
        {
          "text": "天氣有點很熱",
          "error": "Do not use '很' after '有點'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我有點開心",
          "error": "'有點' is usually for negative or neutral feelings; '開心' is positive, so use '很開心'."
        }
      ],
      "transformation_drills": ["Change '天氣很熱' to '天氣有點熱'", "Change '心情不好' to '心情有點不好'"],
      "production_drills": ["Say you feel a little tired using '有點'", "Describe the weather as a little cold"],
      "common_error_patterns": ["Using '有點' with positive adjectives", "Adding '很' after '有點'"],
      "repair_feedback": {
        "word_order": "Place '有點' directly before the adjective.",
        "politeness": "Use '有點' to soften complaints.",
        "vocabulary": "Use adjectives like 熱, 冷, 累, 緊張."
      }
    },
    {
      "pattern": "Subject + 太 + Adjective + 了",
      "structure": ["Subject", "太", "Adjective", "了"],
      "explanation_en": "Use '太...了' to express that something is 'too' much or excessive, often with a sense of complaint or strong feeling.",
      "title": "太 + Adjective + 了",
      "meaning": "Too [adjective] (excessive)",
      "when_to_use": ["Complaining about weather or mood", "Expressing strong feelings (positive or negative)"],
      "when_not_to_use": ["For neutral descriptions (use '很')", "When you want to be polite (use '有點')"],
      "pragmatic_notes": "In Taiwan, '太...了' is common for strong complaints like '天氣太熱了' or positive exclamations like '太好了'.",
      "word_order_notes": "Subject + 太 + Adjective + 了. The '了' is mandatory for this pattern.",
      "english_contrast": "English uses 'too' before the adjective. Chinese uses '太' before and '了' at the end.",
      "korean_contrast": "Korean uses '너무 + Adjective + 아/어요'. Chinese uses '太 + Adjective + 了'.",
      "negative_examples": [
        {
          "text": "天氣太熱",
          "error": "Missing '了' makes the sentence incomplete."
        }
      ],
      "incorrect_examples": [
        {
          "text": "天氣太冷了",
          "error": "This is actually correct; no error here."
        }
      ],
      "transformation_drills": ["Change '天氣很熱' to '天氣太熱了'", "Change '心情有點不好' to '心情太不好了'"],
      "production_drills": ["Complain that the weather is too hot", "Say you are too tired using '太...了'"],
      "common_error_patterns": ["Omitting '了' at the end", "Using '太' with positive adjectives without context"],
      "repair_feedback": {
        "word_order": "Place '太' before the adjective and '了' at the end.",
        "politeness": "Use '太...了' carefully as it can sound strong; use '有點' for polite complaints.",
        "vocabulary": "Use adjectives like 熱, 冷, 累, 貴."
      }
    }
  ]
}
